import { useState, useEffect, useRef } from "react";

/* ── Cute LINE-sticker style bear ── */
const Bear = ({ pose = "normal", size = 220 }) => {
  const poses = {
    normal:   <BearNormal  size={size} />,
    blush:    <BearBlush   size={size} />,
    sad:      <BearSad     size={size} />,
    cry:      <BearCry     size={size} />,
    cover:    <BearCover   size={size} />,
    kiss:     <BearKiss    size={size} />,
  };
  return poses[pose] || poses.normal;
};

const BearBase = ({ size, children }) => (
  <svg width={size} height={size} viewBox="0 0 240 240" fill="none" xmlns="http://www.w3.org/2000/svg">
    {children}
  </svg>
);

/* Shared body/head shapes */
const Body = () => (
  <>
    {/* Body */}
    <ellipse cx="120" cy="185" rx="58" ry="48" fill="#A0522D"/>
    <ellipse cx="120" cy="185" rx="58" ry="48" fill="url(#bodyGrad)"/>
    {/* Belly */}
    <ellipse cx="120" cy="190" rx="34" ry="30" fill="#D2956A"/>
    {/* Arms */}
    <ellipse cx="68" cy="188" rx="20" ry="13" fill="#A0522D" transform="rotate(-30 68 188)"/>
    <ellipse cx="172" cy="188" rx="20" ry="13" fill="#A0522D" transform="rotate(30 172 188)"/>
    <defs>
      <linearGradient id="bodyGrad" x1="80" y1="150" x2="160" y2="220" gradientUnits="userSpaceOnUse">
        <stop offset="0%" stopColor="#C8703A"/>
        <stop offset="100%" stopColor="#8B4513"/>
      </linearGradient>
      <linearGradient id="headGrad" x1="80" y1="40" x2="160" y2="140" gradientUnits="userSpaceOnUse">
        <stop offset="0%" stopColor="#C8703A"/>
        <stop offset="100%" stopColor="#A0522D"/>
      </linearGradient>
    </defs>
  </>
);

const Head = ({ children }) => (
  <>
    {/* Ears */}
    <circle cx="68"  cy="62" r="22" fill="#A0522D" stroke="#5C2E0A" strokeWidth="4"/>
    <circle cx="68"  cy="62" r="13" fill="#D2956A"/>
    <circle cx="172" cy="62" r="22" fill="#A0522D" stroke="#5C2E0A" strokeWidth="4"/>
    <circle cx="172" cy="62" r="13" fill="#D2956A"/>
    {/* Head */}
    <circle cx="120" cy="110" r="68" fill="url(#headGrad)" stroke="#5C2E0A" strokeWidth="4"/>
    {/* Muzzle */}
    <ellipse cx="120" cy="128" rx="30" ry="22" fill="#D2956A"/>
    {/* Nose */}
    <ellipse cx="120" cy="118" rx="9"  ry="6"  fill="#3D1C00"/>
    {children}
  </>
);

const Cheeks = ({ opacity = 0.5 }) => (
  <>
    <ellipse cx="86"  cy="130" rx="14" ry="9" fill="#FF8FAB" opacity={opacity}/>
    <ellipse cx="154" cy="130" rx="14" ry="9" fill="#FF8FAB" opacity={opacity}/>
  </>
);

/* Bear with hearts floating */
