/* Confetti */
const Confetti = () => (
  <div style={{position:"fixed",inset:0,pointerEvents:"none",overflow:"hidden",zIndex:50}}>
    {Array.from({length:50},(_,i)=>(
      <div key={i} style={{
        position:"absolute",
        left:`${(i*7.3+5)%100}%`,
        top:"-30px",
        fontSize:`${13+(i%14)}px`,
        animation:`cfFall ${1.8+(i%3)*0.9}s ${(i*0.11)%2.8}s linear infinite`,
      }}>
        {["🌸","💕","✨","💖","🎀","💝","🌷","💗","🎊","🩷","❤️","🎉"][i%12]}
      </div>
    ))}
  </div>
);

const msgs = [
  { text: "Wach ya zina dyali intissar mzalk thabini? 🥺", pose: "blush" },
  { text: "Wach man naytak 💔😔?",                          pose: "sad"   },
  { text: "But i love yooo 🫠🥹",                          pose: "cry"   },
  { text: "PLEASE ya lmakloba 🫠💗!!",                     pose: "cover" },
];

export default function App() {
  const [step, setStep]       = useState(0);
  const [done, setDone]       = useState(false);
  const [msgKey, setMsgKey]   = useState(0);

  const yesScales = [1, 1.5, 2.1, 3.0];
  const noScales  = [1, 0.72, 0.44, 0.14];
  const ys = yesScales[Math.min(step, 3)];
  const ns = noScales[Math.min(step, 3)];

  const handleNo = () => {
    if (step < 3) { setStep(s => s + 1); setMsgKey(k => k + 1); }
  };

  const { text, pose } = msgs[Math.min(step, 3)];

  return (
    <div style={{
      minHeight: "100vh",
      background: done
        ? "linear-gradient(145deg,#ffe4f0,#ffc8dc,#ffb0ce)"
        : "#F5F0EE",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      padding: "32px 20px",
      fontFamily: "'Nunito','Quicksand','Comic Sans MS',sans-serif",
      position: "relative", overflow: "hidden",
      transition: "background 1.2s ease",
    }}>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@700;800;900&display=swap');

        @keyframes cfFall  { 0%{transform:translateY(0) rotate(0);opacity:1} 100%{transform:translateY(110vh) rotate(540deg);opacity:0} }
        @keyframes bearBob { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-10px)} }
        @keyframes msgIn   { 0%{opacity:0;transform:scale(.88) translateY(8px)} 60%{transform:scale(1.04)} 100%{opacity:1;transform:scale(1) translateY(0)} }
        @keyframes pulse   { 0%,100%{transform:scale(1)} 50%{transform:scale(1.12)} }
        @keyframes fpulse  { 0%,100%{transform:scale(1)} 50%{transform:scale(1.18)} }
        @keyframes winIn   { from{opacity:0;transform:translateY(30px)} to{opacity:1;transform:translateY(0)} }
        @keyframes hf1     { 0%,100%{transform:translateY(0) scale(1)} 50%{transform:translateY(-8px) scale(1.1)} }
        @keyframes hf2     { 0%,100%{transform:translateY(0) scale(1)} 50%{transform:translateY(-10px) scale(1.15)} }
        @keyframes glow    { 0%,100%{text-shadow:0 0 16px #FF4D7A} 50%{text-shadow:0 0 32px #FF1A5E,0 0 60px #FF85A1} }
        @keyframes kissFloat { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-8px)} }
      `}</style>

      {done ? (
        <>
          <Confetti/>
          {/* Kissing bears GIF */}
          <div style={{animation:"winIn .6s ease, kissFloat 1.4s ease-in-out infinite"}}>
            <img src="data:image/gif;base64," alt="kissing bears" style={{width:260,height:"auto",display:"block"}}/>
          </div>

          <div style={{
            marginTop:8, textAlign:"center",
            fontSize:"clamp(18px,4.5vw,26px)",
            fontWeight:900, color:"#C0002A",
            animation:"glow 1.6s ease-in-out infinite, winIn .5s ease",
            lineHeight:1.4,
          }}>
            I knew you love me ya lmakloba 😂❤️🫠
          </div>
          <div style={{fontSize:"clamp(14px,3.5vw,20px)",color:"#E05C7A",fontWeight:700,marginTop:8,animation:"winIn .5s .25s both ease"}}>
            I love you too 💕🎀
          </div>
          <div style={{fontSize:32,marginTop:12,animation:"hf1 1s ease-in-out infinite alternate"}}>
            🎊💖🎉💗🎀✨
          </div>
        </>
      ) : (
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:28,width:"100%",maxWidth:400}}>

          {/* Bear GIF */}
          <div style={{animation:`bearBob ${step>=2?"0.75s":"1.4s"} ease-in-out infinite`}}>
            <img
              src="data:image/gif;base64,"
              alt="milk and mocha bears"
              style={{width:220, height:"auto", display:"block"}}
            />
          </div>

          {/* Message */}
          <div key={msgKey} style={{
            fontSize:"clamp(16px,4.2vw,22px)",
            fontWeight:800,
            color:"#D63065",
            textAlign:"center",
            lineHeight:1.55,
            animation:`msgIn .45s ease, ${step>=3?"fpulse .45s":"pulse .9s"} ease-in-out infinite`,
            padding:"0 8px",
          }}>
            {text}
          </div>

          {/* Buttons */}
          <div style={{display:"flex",gap:16,alignItems:"center",justifyContent:"center",flexWrap:"wrap"}}>

            {/* YES */}
            <button
              onClick={()=>setDone(true)}
              style={{
                transform:`scale(${ys})`,
                transformOrigin:"center",
                background:"#E8407A",
                color:"white",
                border:"none",
                borderRadius:50,
                padding:"16px 44px",
                fontSize:18,
                fontFamily:"inherit",
                fontWeight:800,
                cursor:"pointer",
                boxShadow:"0 6px 24px rgba(232,64,122,0.45)",
                transition:"transform .5s cubic-bezier(.34,1.56,.64,1)",
                animation: step>=1 ? `${step>=3?"fpulse .45s":"pulse .9s"} ease-in-out infinite` : "none",
                letterSpacing:"1px",
              }}
            >
              AH 💖
            </button>

            {/* NO */}
            <button
              onClick={handleNo}
              style={{
                transform:`scale(${ns})`,
                transformOrigin:"center",
                background:"white",
                color:"#999",
                border:"2.5px solid #DDD",
                borderRadius:50,
                padding:"14px 36px",
                fontSize:16,
                fontFamily:"inherit",
                fontWeight:700,
                cursor: step>=3?"not-allowed":"pointer",
                transition:"transform .5s cubic-bezier(.34,1.56,.64,1)",
                opacity: Math.max(ns, 0.06),
                pointerEvents: step>=3?"none":"auto",
              }}
            >
              LA 🙅
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
